import{_ as o,o as l,c as e,a0 as i}from"./chunks/framework.Dx25mwie.js";const m=JSON.parse('{"title":"代理工具","description":"","frontmatter":{},"headers":[],"relativePath":"guide/proxy.md","filePath":"guide/proxy.md"}'),r={name:"guide/proxy.md"};function t(d,a,s,n,h,c){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="代理工具" tabindex="-1">代理工具 <a class="header-anchor" href="#代理工具" aria-label="Permalink to &quot;代理工具&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>代理工具基于 <a href="https://github.com/MetaCubeX/mihomo" target="_blank" rel="noreferrer">Mihomo</a> 内核，提供一键启停、配置管理、系统代理设置等功能。</p><div class="tip custom-block"><p class="custom-block-title">安装代理工具</p><p>首次使用需要在 <strong>工具商店</strong> 中安装 ProxyTools 插件。</p></div><h2 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h2><ul><li><strong>一键启停</strong> — 点击按钮即可启动/停止代理</li><li><strong>状态监控</strong> — 实时显示代理运行状态（绿灯/红灯）</li><li><strong>配置管理</strong> — 支持上传配置文件（YAML 格式）和在线编辑</li><li><strong>系统代理</strong> — 自动设置/清除 Windows 系统代理</li><li><strong>Dashboard</strong> — 内置 MetaCubeXD 面板，端口 19090</li></ul><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><h3 id="_1-安装插件" tabindex="-1">1. 安装插件 <a class="header-anchor" href="#_1-安装插件" aria-label="Permalink to &quot;1. 安装插件&quot;">​</a></h3><ol><li>点击左侧导航栏「工具商店」</li><li>找到 ProxyTools 卡片，点击「安装」</li><li>等待下载完成，左侧导航栏将出现「代理工具」</li></ol><h3 id="_2-配置代理" tabindex="-1">2. 配置代理 <a class="header-anchor" href="#_2-配置代理" aria-label="Permalink to &quot;2. 配置代理&quot;">​</a></h3><ol><li>进入「代理工具」页面</li><li>点击「上传配置」选择 <code>.yaml</code> 配置文件</li><li>或点击「编辑配置」在线修改</li></ol><h3 id="_3-启动代理" tabindex="-1">3. 启动代理 <a class="header-anchor" href="#_3-启动代理" aria-label="Permalink to &quot;3. 启动代理&quot;">​</a></h3><ol><li>点击「启动」按钮</li><li>状态指示灯变为绿色表示运行中</li><li>系统代理自动设置</li></ol><h3 id="_4-dashboard" tabindex="-1">4. Dashboard <a class="header-anchor" href="#_4-dashboard" aria-label="Permalink to &quot;4. Dashboard&quot;">​</a></h3><p>代理运行后，可通过以下地址访问面板：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:19090/ui</span></span></code></pre></div><h2 id="配置文件" tabindex="-1">配置文件 <a class="header-anchor" href="#配置文件" aria-label="Permalink to &quot;配置文件&quot;">​</a></h2><p>配置文件保存在 <code>%APPDATA%\\ToolboxWinUI\\proxy\\config.yaml</code>。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>配置文件会自动追加以下必要字段，请勿手动删除：</p><ul><li><code>mixed-port: 7890</code>（混合端口）</li><li><code>allow-lan: false</code>（不允许局域网连接）</li><li><code>mode: rule</code>（规则模式）</li><li><code>external-controller: 0.0.0.0:9097</code>（REST API 端口）</li><li><code>log-file: logs/run.log</code>（日志文件）</li></ul></div><h2 id="mihomo-内核" tabindex="-1">Mihomo 内核 <a class="header-anchor" href="#mihomo-内核" aria-label="Permalink to &quot;Mihomo 内核&quot;">​</a></h2><ul><li><strong>版本</strong>: v1.19.11</li><li><strong>内核文件</strong>: <code>ProxyTools/mihomo/mihomo.exe</code></li><li><strong>地理数据</strong>: <code>ProxyTools/mihomo/country.mmdb</code>、<code>geo.mmdb</code>、<code>geoSite.dat</code></li></ul><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><h3 id="代理无法启动" tabindex="-1">代理无法启动 <a class="header-anchor" href="#代理无法启动" aria-label="Permalink to &quot;代理无法启动&quot;">​</a></h3><ol><li>检查端口 7890 是否被占用</li><li>检查配置文件格式是否正确</li><li>查看日志文件 <code>logs/run.log</code></li></ol><h3 id="无法访问-dashboard" tabindex="-1">无法访问 Dashboard <a class="header-anchor" href="#无法访问-dashboard" aria-label="Permalink to &quot;无法访问 Dashboard&quot;">​</a></h3><ol><li>确认代理已启动</li><li>检查端口 19090 是否被占用</li><li>尝试访问 <code>http://127.0.0.1:9097</code> 检查 REST API</li></ol>',26)])])}const b=o(r,[["render",t]]);export{m as __pageData,b as default};
